#pragma once
// Builtin tool recipes — one line per tool for easy editing.
// To add a tool, add a new JSON object before the closing ].
inline const char* BUILTIN_RECIPES = R"JSON([{"name":"fzf","desc":"fuzzy finder","check":"fzf","install":"[ -d $HOME/.fzf ] || { git clone --depth=1 https://github.com/junegunn/fzf.git $HOME/.fzf && $HOME/.fzf/install --all --no-update-rc; }"},{"name":"trzsz","desc":"trz/tsz — file transfer","check":"trz","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/trzsz/trzsz-go/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/trzsz/trzsz-go/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && v=${ver#v} && curl -fsSL https://github.com/trzsz/trzsz-go/releases/download/$ver/trzsz_${v}_linux_x86_64.tar.gz -o /tmp/trzsz.tar.gz && tar -xzf /tmp/trzsz.tar.gz -C /tmp && cp /tmp/trzsz_${v}_linux_x86_64/trz /tmp/trzsz_${v}_linux_x86_64/tsz $HOME/.local/bin/"},{"name":"ohmyposh","desc":"prompt theme engine","check":"oh-my-posh","install":"mkdir -p $HOME/.local/bin && curl -fsSL https://github.com/JanDeDobbeleer/oh-my-posh/releases/latest/download/posh-linux-amd64 -o $HOME/.local/bin/oh-my-posh && chmod +x $HOME/.local/bin/oh-my-posh"},{"name":"ohmyzsh","desc":"Oh My Zsh framework","check":"test -d $HOME/.oh-my-zsh","install":"ZSH_CUSTOM=${ZSH_CUSTOM:-$HOME/.oh-my-zsh/custom} && (sh -c \"$(curl -fsSL https://raw.githubusercontent.com/ohmyzsh/ohmyzsh/master/tools/install.sh)\" \"\" --unattended || true) && [ -d $ZSH_CUSTOM/plugins/zsh-autosuggestions ] || git clone --depth=1 https://github.com/zsh-users/zsh-autosuggestions.git $ZSH_CUSTOM/plugins/zsh-autosuggestions && [ -d $ZSH_CUSTOM/plugins/zsh-syntax-highlighting ] || git clone --depth=1 https://github.com/zsh-users/zsh-syntax-highlighting.git $ZSH_CUSTOM/plugins/zsh-syntax-highlighting && [ -d $ZSH_CUSTOM/plugins/z ] || git clone --depth=1 https://github.com/agkozak/zsh-z.git $ZSH_CUSTOM/plugins/z"},{"name":"zoxide","desc":"smarter cd (z command)","check":"zoxide","install":"curl -fsSL https://raw.githubusercontent.com/ajeetdsouza/zoxide/master/install.sh | sh"},{"name":"starship","desc":"cross-shell prompt","check":"starship","install":"curl -fsSL https://starship.rs/install.sh | sh -s -- -y"},{"name":"nvim","desc":"neovim editor","check":"nvim","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/neovim/neovim/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/neovim/neovim/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && [ -n \"$ver\" ] && curl -fsSL https://github.com/neovim/neovim/releases/download/$ver/nvim-linux-x86_64.tar.gz -o /tmp/nvim.tar.gz && rm -rf $HOME/.local/nvim-linux-x86_64 && tar -xzf /tmp/nvim.tar.gz -C $HOME/.local && ln -sf $HOME/.local/nvim-linux-x86_64/bin/nvim $HOME/.local/bin/nvim"},{"name":"rg","desc":"ripgrep","check":"rg","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/BurntSushi/ripgrep/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/BurntSushi/ripgrep/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && v=${ver#v} && curl -fsSL https://github.com/BurntSushi/ripgrep/releases/download/$ver/ripgrep-$v-x86_64-unknown-linux-musl.tar.gz -o /tmp/rg.tar.gz && tar -xzf /tmp/rg.tar.gz -C /tmp && cp /tmp/ripgrep-$v-x86_64-unknown-linux-musl/rg $HOME/.local/bin/rg"},{"name":"fd","desc":"fd — fast find","check":"fd","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/sharkdp/fd/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/sharkdp/fd/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && curl -fsSL https://github.com/sharkdp/fd/releases/download/$ver/fd-$ver-x86_64-unknown-linux-musl.tar.gz -o /tmp/fd.tar.gz && tar -xzf /tmp/fd.tar.gz -C /tmp && cp /tmp/fd-$ver-x86_64-unknown-linux-musl/fd $HOME/.local/bin/fd"},{"name":"bat","desc":"bat — cat with highlighting","check":"bat","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/sharkdp/bat/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/sharkdp/bat/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && curl -fsSL https://github.com/sharkdp/bat/releases/download/$ver/bat-$ver-x86_64-unknown-linux-musl.tar.gz -o /tmp/bat.tar.gz && tar -xzf /tmp/bat.tar.gz -C /tmp && cp /tmp/bat-$ver-x86_64-unknown-linux-musl/bat $HOME/.local/bin/bat"},{"name":"delta","desc":"delta — better git diff","check":"delta","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/dandavison/delta/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/dandavison/delta/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && v=${ver#v} && curl -fsSL https://github.com/dandavison/delta/releases/download/$ver/delta-$v-x86_64-unknown-linux-gnu.tar.gz -o /tmp/delta.tar.gz && tar -xzf /tmp/delta.tar.gz -C /tmp && cp /tmp/delta-$v-x86_64-unknown-linux-gnu/delta $HOME/.local/bin/delta"},{"name":"eza","desc":"eza — modern ls","check":"eza","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/eza-community/eza/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/eza-community/eza/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && curl -fsSL https://github.com/eza-community/eza/releases/download/$ver/eza_x86_64-unknown-linux-musl.tar.gz -o /tmp/eza.tar.gz && tar -xzf /tmp/eza.tar.gz -C /tmp && cp /tmp/eza $HOME/.local/bin/eza"},{"name":"lazygit","desc":"terminal git UI","check":"lazygit","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/jesseduffield/lazygit/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/jesseduffield/lazygit/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && v=${ver#v} && curl -fsSL https://github.com/jesseduffield/lazygit/releases/download/$ver/lazygit_${v}_Linux_x86_64.tar.gz -o /tmp/lazygit.tar.gz && tar -xzf /tmp/lazygit.tar.gz -C /tmp lazygit && cp /tmp/lazygit $HOME/.local/bin/lazygit"},{"name":"gcc","desc":"GNU C compiler","check":"gcc"},{"name":"g++","desc":"GNU C++ compiler","check":"g++"},{"name":"clang","desc":"LLVM C compiler","check":"clang"},{"name":"clangd","desc":"C/C++ LSP server","check":"clangd","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/clangd/clangd/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/clangd/clangd/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && curl -fsSL https://github.com/clangd/clangd/releases/download/$ver/clangd-linux-$ver.zip -o /tmp/clangd.zip && unzip -o /tmp/clangd.zip -d /tmp/clangd && cp /tmp/clangd/clangd_*/bin/clangd $HOME/.local/bin/clangd"},{"name":"xmake","desc":"xmake build system","check":"xmake","install":"curl -fsSL https://xmake.io/shget.text | bash"},{"name":"cmake","desc":"CMake build system","check":"cmake","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/Kitware/CMake/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/Kitware/CMake/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && v=${ver#v} && curl -fsSL https://github.com/Kitware/CMake/releases/download/$ver/cmake-$v-linux-x86_64.tar.gz -o /tmp/cmake.tar.gz && tar -xzf /tmp/cmake.tar.gz -C /tmp && cp /tmp/cmake-$v-linux-x86_64/bin/cmake $HOME/.local/bin/cmake"},{"name":"make","desc":"GNU Make","check":"make"},{"name":"gdb","desc":"GNU debugger","check":"gdb"},{"name":"go","desc":"go compiler","check":"go","install":"curl -fsSL https://go.dev/dl/go1.26.2.linux-amd64.tar.gz -o /tmp/go.tar.gz && rm -rf $HOME/.local/go && tar -C $HOME/.local -xzf /tmp/go.tar.gz"},{"name":"gopls","desc":"Go LSP server","check":"gopls","install":"GOBIN=$HOME/.local/bin GOPROXY=https://goproxy.io,direct go install golang.org/x/tools/gopls@latest"},{"name":"delve","desc":"Go debugger (dlv)","check":"dlv","install":"GOBIN=$HOME/.local/bin GOPROXY=https://goproxy.io,direct go install github.com/go-delve/delve/cmd/dlv@latest"},{"name":"python","desc":"Python 3","check":"python3"},{"name":"uv","desc":"uv — fast Python pkg mgr","check":"uv","install":"curl -fsSL https://astral.sh/uv/install.sh | sh"},{"name":"ruff","desc":"ruff — Python linter","check":"ruff","install":"curl -fsSL https://astral.sh/ruff/install.sh | sh"},{"name":"pyright","desc":"Python type checker","check":"which pyright","install":"which uv >/dev/null 2>&1 || curl -fsSL https://astral.sh/uv/install.sh | sh; uv tool install pyright 2>/dev/null || pipx install pyright 2>/dev/null || npm install -g pyright 2>/dev/null || true"},{"name":"rust","desc":"rust via rustup","check":"rustc","install":"curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh -s -- -y"},{"name":"rust-analyzer","desc":"Rust LSP server","check":"rust-analyzer","install":"curl -fsSL https://github.com/rust-lang/rust-analyzer/releases/latest/download/rust-analyzer-x86_64-unknown-linux-gnu.gz -o /tmp/ra.gz && gunzip -f /tmp/ra.gz && mv /tmp/ra $HOME/.local/bin/rust-analyzer && chmod +x $HOME/.local/bin/rust-analyzer"},{"name":"node","desc":"node.js via nvm","check":"node","install":"[ -s \"$HOME/.nvm/nvm.sh\" ] || { rm -rf \"$HOME/.nvm\" && curl -fsSL -o- https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.1/install.sh | bash; } && export NVM_DIR=\"$HOME/.nvm\" && . \"$NVM_DIR/nvm.sh\" && nvm install --lts || true"},{"name":"bun","desc":"bun runtime","check":"bun","install":"curl -fsSL https://bun.sh/install | bash"},{"name":"xclip","desc":"system clipboard (X11)","check":"xclip"},{"name":"tree-sitter","desc":"tree-sitter CLI","check":"tree-sitter","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/tree-sitter/tree-sitter/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/tree-sitter/tree-sitter/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && curl -fsSL https://github.com/tree-sitter/tree-sitter/releases/download/$ver/tree-sitter-linux-x64.gz -o /tmp/ts.gz && gunzip -f /tmp/ts.gz && mv /tmp/ts $HOME/.local/bin/tree-sitter && chmod +x $HOME/.local/bin/tree-sitter"},{"name":"mihomo","desc":"proxy (clash meta)","check":"mihomo","install":"if [ -n \"$GITHUB_TOKEN\" ]; then ver=$(curl -sL -H \"Authorization: token $GITHUB_TOKEN\" https://api.github.com/repos/MetaCubeX/mihomo/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); else ver=$(curl -sL https://api.github.com/repos/MetaCubeX/mihomo/releases/latest | grep tag_name | head -1 | cut -d'\"' -f4); fi && curl -fsSL https://github.com/MetaCubeX/mihomo/releases/download/$ver/mihomo-linux-amd64-$ver.gz -o /tmp/mihomo.gz && gunzip -f /tmp/mihomo.gz && mv /tmp/mihomo $HOME/.local/bin/mihomo && chmod +x $HOME/.local/bin/mihomo"},{"name":"htop","desc":"process viewer","check":"htop"},{"name":"netstat","desc":"network statistics","check":"netstat"},{"name":"ping","desc":"network reachability","check":"ping"},{"name":"curl","desc":"HTTP client","check":"curl"},{"name":"unzip","desc":"unzip archives","check":"unzip"},{"name":"docker","desc":"docker engine","check":"docker","install":"curl -fsSL https://get.docker.com | sh","needs_sudo":true},{"name":"tmux","desc":"terminal multiplexer","check":"tmux"},{"name":"zsh","desc":"z shell","check":"zsh"},{"name":"git","desc":"git","check":"git"}]
)JSON";
